// MARK: - Keychain Manager
class KeychainManager {
    static let shared = KeychainManager()
    private init() {}
    
    func savePrivateKey(_ privateKey: Data, forAccount account: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: account,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
            kSecValueData as String: privateKey
        ]
        
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    func loadPrivateKey(forAccount account: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: account,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            return nil
        }
        return data
    }
    
    func deletePrivateKey(forAccount account: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: account
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        return status == errSecSuccess
    }
}

// MARK: - Crypto Utilities
class CryptoUtilities {
    static func generatePrivateKey() -> Data {
        var bytes = [UInt8](repeating: 0, count: 32)
        _ = SecRandomCopyBytes(kSecRandomDefault, bytes.count, &bytes)
        return Data(bytes)
    }
    
    static func derivePublicKey(from privateKey: Data) -> Data? {
        guard privateKey.count == 32 else { return nil }
        
        var publicKeyBytes = secp256k1_pubkey()
        let context = secp256k1_context_create(UInt32(SECP256K1_CONTEXT_SIGN | SECP256K1_CONTEXT_VERIFY))
        defer { secp256k1_context_destroy(context) }
        
        let result = privateKey.withUnsafeBytes { privateKeyPtr -> Int32 in
            guard let privateKeyAddress = privateKeyPtr.baseAddress?.assumingMemoryBound(to: UInt8.self) else {
                return 0
            }
            return secp256k1_ec_pubkey_create(context, &publicKeyBytes, privateKeyAddress)
        }
        
        guard result == 1 else { return nil }
        
        var serializedPubKey = [UInt8](repeating: 0, count: 65)
        var outputLen = 65
        secp256k1_ec_pubkey_serialize(context, &serializedPubKey, &outputLen, &publicKeyBytes, UInt32(SECP256K1_EC_UNCOMPRESSED))
        
        return Data(serializedPubKey)
    }
    
    static func generateAddress(from publicKey: Data) -> String {
        let hash = sha256(data: publicKey)
        let ripemd = ripemd160(data: hash)
        
        var addressBytes = Data([0x00])
        addressBytes.append(ripemd)
        
        let checksum = sha256(data: sha256(data: addressBytes)).prefix(4)
        addressBytes.append(checksum)
        
        return base58Encode(addressBytes)
    }
    
    static func sha256(data: Data) -> Data {
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes {
            _ = CC_SHA256($0.baseAddress, CC_LONG(data.count), &hash)
        }
        return Data(hash)
    }
    
    static func ripemd160(data: Data) -> Data {
        var hash = [UInt8](repeating: 0, count: Int(CC_RIPEMD160_DIGEST_LENGTH))
        data.withUnsafeBytes {
            _ = CC_RIPEMD160($0.baseAddress, CC_LONG(data.count), &hash)
        }
        return Data(hash)
    }
    
    static func base58Encode(_ data: Data) -> String {
        let alphabet = "123456789ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz"
        var bytes = [UInt8](data)
        var zerosCount = 0
        
        for byte in bytes {
            if byte != 0 { break }
            zerosCount += 1
        }
        
        let size = bytes.count * 138 / 100 + 1
        var encoded = [UInt8](repeating: 0, count: size)
        
        for byte in bytes {
            var carry = Int(byte)
            var i = 0
            
            for j in stride(from: size - 1, through: 0, by: -1) where carry != 0 || i < size {
                carry += 256 * Int(encoded[j])
                encoded[j] = UInt8(carry % 58)
                carry /= 58
                i += 1
            }
        }
        
        var result = ""
        for _ in 0..<zerosCount {
            result.append("1")
        }
        
        for byte in encoded {
            if byte == 0 && result.isEmpty { continue }
            let index = alphabet.index(alphabet.startIndex, offsetBy: Int(byte))
            result.append(alphabet[index])
        }
        
        return result
    }
    
    static func signTransaction(privateKey: Data, messageHash: Data) -> Data? {
        guard privateKey.count == 32, messageHash.count == 32 else { return nil }
        
        let context = secp256k1_context_create(UInt32(SECP256K1_CONTEXT_SIGN))
        defer { secp256k1_context_destroy(context) }
        
        var signature = secp256k1_ecdsa_signature()
        
        let result = privateKey.withUnsafeBytes { privateKeyPtr -> Int32 in
            messageHash.withUnsafeBytes { messagePtr -> Int32 in
                guard let privateKeyAddress = privateKeyPtr.baseAddress?.assumingMemoryBound(to: UInt8.self),
                      let messageAddress = messagePtr.baseAddress?.assumingMemoryBound(to: UInt8.self) else {
                    return 0
                }
                return secp256k1_ecdsa_sign(context, &signature, messageAddress, privateKeyAddress, nil, nil)
            }
        }
        
        guard result == 1 else { return nil }
        
        var serializedSignature = [UInt8](repeating: 0, count: 64)
        secp256k1_ecdsa_signature_serialize_compact(context, &serializedSignature, &signature)
        
        return Data(serializedSignature)
    }
}

// MARK: - Wallet Model
struct Wallet {
    let address: String
    let publicKey: Data
    private let accountIdentifier: String
    
    init?(accountIdentifier: String = "default_wallet") {
        self.accountIdentifier = accountIdentifier
        
        if let existingPrivateKey = KeychainManager.shared.loadPrivateKey(forAccount: accountIdentifier) {
            guard let pubKey = CryptoUtilities.derivePublicKey(from: existingPrivateKey) else {
                return nil
            }
            self.publicKey = pubKey
            self.address = CryptoUtilities.generateAddress(from: pubKey)
        } else {
            let privateKey = CryptoUtilities.generatePrivateKey()
            guard KeychainManager.shared.savePrivateKey(privateKey, forAccount: accountIdentifier) else {
                return nil
            }
            
            guard let pubKey = CryptoUtilities.derivePublicKey(from: privateKey) else {
                return nil
            }
            self.publicKey = pubKey
            self.address = CryptoUtilities.generateAddress(from: pubKey)
        }
    }
    
    func signTransaction(messageHash: Data) -> Data? {
        guard let privateKey = KeychainManager.shared.loadPrivateKey(forAccount: accountIdentifier) else {
            return nil
        }
        return CryptoUtilities.signTransaction(privateKey: privateKey, messageHash: messageHash)
    }
    
    func exportPrivateKey() -> Data? {
        return KeychainManager.shared.loadPrivateKey(forAccount: accountIdentifier)
    }
}

// MARK: - Transaction Model
struct Transaction {
    let from: String
    let to: String
    let amount: Decimal
    let nonce: UInt64
    let gasPrice: Decimal
    let gasLimit: UInt64
    
    func serialize() -> Data {
        var data = Data()
        data.append(from.data(using: .utf8) ?? Data())
        data.append(to.data(using: .utf8) ?? Data())
        data.append(String(describing: amount).data(using: .utf8) ?? Data())
        data.append(withUnsafeBytes(of: nonce.bigEndian) { Data($0) })
        data.append(String(describing: gasPrice).data(using: .utf8) ?? Data())
        data.append(withUnsafeBytes(of: gasLimit.bigEndian) { Data($0) })
        return data
    }
    
    func hash() -> Data {
        return CryptoUtilities.sha256(data: serialize())
    }
}

struct SignedTransaction {
    let transaction: Transaction
    let signature: Data
    
    func serialize() -> Data {
        var data = transaction.serialize()
        data.append(signature)
        return data
    }
}

