// MARK: - Wallet Manager
class WalletManager {
    static let shared = WalletManager()
    private(set) var currentWallet: Wallet?
    
    private init() {
        loadWallet()
    }
    
    func createWallet() -> Bool {
        guard let wallet = Wallet() else { return false }
        currentWallet = wallet
        return true
    }
    
    func loadWallet() {
        currentWallet = Wallet()
    }
    
    func sendTransaction(to: String, amount: Decimal, gasPrice: Decimal, gasLimit: UInt64, completion: @escaping (Result<String, Error>) -> Void) {
        guard let wallet = currentWallet else {
            completion(.failure(NSError(domain: "No wallet available", code: -1, userInfo: nil)))
            return
        }
        
        BlockchainService.shared.getNonce(address: wallet.address) { result in
            switch result {
            case .success(let nonce):
                let transaction = Transaction(
                    from: wallet.address,
                    to: to,
                    amount: amount,
                    nonce: nonce,
                    gasPrice: gasPrice,
                    gasLimit: gasLimit
                )
                
                let messageHash = transaction.hash()
                
                guard let signature = wallet.signTransaction(messageHash: messageHash) else {
                    completion(.failure(NSError(domain: "Failed to sign transaction", code: -1, userInfo: nil)))
                    return
                }
                
                let signedTransaction = SignedTransaction(transaction: transaction, signature: signature)
                
                BlockchainService.shared.broadcastTransaction(signedTransaction) { result in
                    completion(result)
                }
                
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func getBalance(completion: @escaping (Result<Decimal, Error>) -> Void) {
        guard let wallet = currentWallet else {
            completion(.failure(NSError(domain: "No wallet available", code: -1, userInfo: nil)))
            return
        }
        
        BlockchainService.shared.getBalance(address: wallet.address, completion: completion)
    }
}

