            balanceLabel.topAnchor.constraint(equalTo: addressLabel.bottomAnchor, constant: 20),
            balanceLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            refreshButton.topAnchor.constraint(equalTo: balanceLabel.bottomAnchor, constant: 10),
